import anthropic, json

client = anthropic.Anthropic()

JOURNEY_MAP_TOOL = {
    "name": "record_journey_step",
    "description": "Record one step in a conversational journey map.",
    "input_schema": {
        "type": "object",
        "properties": {
            "stage_id":         {"type": "string"},
            "stage_label":      {"type": "string"},
            "user_action":      {"type": "string"},
            "claude_action":    {"type": ["string", "null"]},
            "emotion":          {"type": "string", "enum": ["anxious","cautious","neutral","hopeful","relieved","frustrated","satisfied"]},
            "pain_points":      {"type": "array", "items": {"type": "string"}},
            "eval_opportunity": {"type": "string"}
        },
        "required": ["stage_id","stage_label","user_action","emotion","pain_points","eval_opportunity"]
    }
}

def generate_journey_map(feature_description: str, persona_brief: str) -> list[dict]:
    """
    Ask Claude to produce a structured journey map for a conversational feature.
    Returns a list of stage dicts, one per conversation step.
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2000,
        tools=[JOURNEY_MAP_TOOL],
        tool_choice={"type": "auto"},
        system=(
            "You are a UX researcher specialising in AI product design. "
            "When given a feature description and persona brief, produce a "
            "conversational journey map by calling record_journey_step once "
            "per stage. Typical maps have 4-6 stages."
        ),
        messages=[{
            "role": "user",
            "content": (
                f"Feature: {feature_description}\n"
                f"Persona: {persona_brief}\n\n"
                "Map the full conversation journey from trigger to closure."
            )
        }]
    )

    steps = []
    for block in response.content:
        if block.type == "tool_use" and block.name == "record_journey_step":
            steps.append(block.input)
    return steps

# Example
steps = generate_journey_map(
    feature_description="Claude-powered legal contract review assistant for solo practitioners",
    persona_brief="Maya Chen, 38, IP attorney, zero-tolerance for hallucinated case citations, fluency=expert"
)
for step in steps:
    print(f"[{step['stage_label']}] emotion={step['emotion']}, pain_points={step['pain_points']}")

import anthropic, json

client = anthropic.Anthropic()

HOT_SPOT_TOOL = {
    "name": "classify_hot_spot",
    "description": "Classify a pain point from a journey map as a specific hot-spot type.",
    "input_schema": {
        "type": "object",
        "properties": {
            "stage_id":      {"type": "string"},
            "pain_point":    {"type": "string"},
            "hot_spot_type": {
                "type": "string",
                "enum": [
                    "context_loss",       # Multi-turn context drift
                    "hallucination_risk", # Model may fabricate facts
                    "trust_gap",          # User unsure whether to trust output
                    "scope_creep",        # Task expands beyond designed scope
                    "format_mismatch",    # Output format not suitable for downstream use
                    "latency_friction",   # Response too slow for the use case
                    "input_constraint"    # User struggles to supply required input
                ]
            },
            "severity":     {"type": "string", "enum": ["high","medium","low"]},
            "mitigation":   {"type": "string"}
        },
        "required": ["stage_id","pain_point","hot_spot_type","severity","mitigation"]
    }
}

def analyse_hot_spots(journey_steps: list[dict]) -> list[dict]:
    """Convert journey map pain points into classified hot spots with mitigations."""
    pain_points_text = "\n".join(
        f"- Stage '{s['stage_label']}': {pp}"
        for s in journey_steps
        for pp in s.get("pain_points", [])
    )
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2000,
        tools=[HOT_SPOT_TOOL],
        tool_choice={"type": "auto"},
        messages=[{
            "role": "user",
            "content": (
                "Classify each pain point below as a hot-spot type and propose a mitigation.\n\n"
                + pain_points_text
            )
        }]
    )
    return [b.input for b in response.content if b.type == "tool_use" and b.name == "classify_hot_spot"]
